/* Minimal GIMPLE pass to count basic blocks per function.
   This implements the basic pattern for a GCC optimization pass.

   References:
   - gcc/tree-pass.h: Pass infrastructure definitions
   - gcc/tree-ssa-dce.cc: Example pass implementation
*/

#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "cfghooks.h"
#include "tree-pass.h"
#include "dumpfile.h"

namespace {

/* Pass metadata. Defines pass properties and behavior. */
const pass_data pass_data_count_bbs =
{
  GIMPLE_PASS,              /* type */
  "count_bbs",              /* name */
  OPTGROUP_NONE,            /* optinfo_flags */
  TV_NONE,                  /* tv_id */
  (PROP_cfg),               /* properties_required */
  0,                        /* properties_provided */
  0,                        /* properties_destroyed */
  0,                        /* todo_flags_start */
  0,                        /* todo_flags_finish */
};

/* Pass implementation class. Inherits from gimple_opt_pass. */
class pass_count_bbs : public gimple_opt_pass
{
public:
  pass_count_bbs (gcc::context *ctxt)
    : gimple_opt_pass (pass_data_count_bbs, ctxt)
  {}

  /* Virtual methods: */

  /* gate() determines if the pass should run.
     Returns true to enable the pass, false to skip it. */
  virtual bool
  gate (function *) final override
  {
    return true;  /* Always run this pass */
  }

  /* execute() performs the actual optimization.
     Returns bitwise OR of TODO_* flags for additional work. */
  virtual unsigned int
  execute (function *fun) final override
  {
    /* Count basic blocks in the function's control flow graph. */
    int bb_count = 0;
    basic_block bb;

    /* Iterate over all basic blocks in the function.
       FOR_EACH_BB_FN is a macro from GCC that iterates blocks. */
    FOR_EACH_BB_FN (bb, fun)
      {
        bb_count++;
      }

    /* Output debug information if dump file is available.
       dump_file is a FILE* set by GCC's pass manager.
       dump_flags contains flags controlling output verbosity. */
    if (dump_file)
      {
        fprintf (dump_file, "Function %s has %d basic blocks\n",
                 function_name (fun), bb_count);
      }

    /* No modifications made, so return 0 (no TODOs). */
    return 0;
  }

  /* clone() creates a copy of this pass for multiple instances.
     Required method for passes. */
  virtual opt_pass *
  clone () final override
  {
    return new pass_count_bbs (m_ctxt);
  }
};

} // namespace

/* Factory function to create an instance of the pass.
   This follows the pattern defined in gcc/tree-pass.h.
   Called by the pass manager to instantiate the pass. */
gimple_opt_pass *
make_pass_count_bbs (gcc::context *ctxt)
{
  return new pass_count_bbs (ctxt);
}

